  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        kind: "quote" as const,
        items: [{ kind: "staff" as const }],
      },
    ],
  };
  expect(processScenario(scenario)).toEqual({
    results: [{ kind: "quote", premium: 93 }],
  });
});

